esqlQuery.esql:
FROM metrics-redisreceiver.otel-*
| WHERE data_stream.dataset == "redisreceiver.otel"
  AND redis.slaves.connected IS NOT NULL
// Filter to primaries: role is primary when attributes.role exists, or check replication metrics
// redis.slaves.connected is only relevant on primaries (replicas report 0)
| STATS connected_replicas = MAX(redis.slaves.connected)
  BY server.address, server.port
// Alert when a primary expects replicas but has none (adjust if standalone is acceptable)
// Use 0 to alert on any instance with zero replicas; for HA setups this indicates risk
| WHERE connected_replicas == 0
| SORT server.address ASC
